/* BTDropdownMenu styles — Figma 736-1793 (panel) + 736-1848 (item).
   All colours via @btech/tokens CSS vars — no hex fallbacks.
   Exception: drop shadow rgba values (not tokenised). */

/* ── Panel ────────────────────────────────────────────────────────────────── */
.bt-dropdown-menu__panel {
  position: fixed;
  z-index: 1000;
  background: var(--bg-primary);
  border-radius: var(--radius-xs);
  box-shadow:
    0 2px 2px rgba(0, 0, 0, 0.06),
    0 4px 3px rgba(0, 0, 0, 0.10);
  padding: var(--space-xs);
  display: flex;
  flex-direction: column;
  opacity: 0;
  pointer-events: none;
  box-sizing: border-box;
  font-family: var(--typography-font-family-sans);
}

/* Becomes visible after positionPopover() runs */
.bt-dropdown-menu__panel--visible {
  opacity: 1;
  pointer-events: auto;
}

/* ── Search area ──────────────────────────────────────────────────────────── */
.bt-dropdown-menu__search {
  padding: var(--space-xs) var(--space-xs) var(--space-sm);
  flex-shrink: 0;
}

/* ── Items scroll container ──────────────────────────────────────────────── */
.bt-dropdown-menu__items {
  max-height: 240px;
  display: flex;
  flex-direction: column;
}

/* ── Item row ────────────────────────────────────────────────────────────── */
.bt-dropdown-menu__item {
  display: flex;
  align-items: center;
  gap: var(--space-xs);
  padding: var(--space-sm);
  border-radius: var(--radius-md);
  cursor: pointer;
  user-select: none;
  color: var(--text-primary);
}

.bt-dropdown-menu__item:hover:not(.bt-dropdown-menu__item--disabled) {
  background: var(--bg-secondary);
}

.bt-dropdown-menu__item:active:not(.bt-dropdown-menu__item--disabled) {
  background: var(--bg-secondary);
}

.bt-dropdown-menu__item--error:not(.bt-dropdown-menu__item--disabled) {
  color: var(--color-ext-error);
}

.bt-dropdown-menu__item--disabled {
  color: var(--text-disabled);
  cursor: not-allowed;
}

/* ── Icon wrapper (16×16, inherits color for currentColor icons) ─────────── */
.bt-dropdown-menu__icon-wrap {
  display: flex;
  align-items: center;
  justify-content: center;
  width: 16px;
  height: 16px;
  flex-shrink: 0;
}

.bt-dropdown-menu__icon-wrap svg,
.bt-dropdown-menu__icon-wrap img {
  width: 16px;
  height: 16px;
}

/* ── Text block (label + optional subtext) ───────────────────────────────── */
.bt-dropdown-menu__item-text {
  display: flex;
  flex-direction: column;
  gap: var(--space-2xs);
  flex: 1;
  min-width: 0;
}

.bt-dropdown-menu__item-label {
  font-size: var(--typography-font-size-sm);
  font-weight: 500;
  line-height: var(--typography-line-height-xs);
}

.bt-dropdown-menu__item-subtext {
  font-size: var(--typography-font-size-xs);
  font-weight: 500;
  line-height: var(--typography-line-height-xs);
  color: var(--text-secondary);
}

/* ── Kbd shortcut badges ─────────────────────────────────────────────────── */
.bt-dropdown-menu__kbd {
  display: flex;
  gap: var(--space-2xs);
  flex-shrink: 0;
  align-items: center;
}

/* ── Group label (section header) ────────────────────────────────────────── */
.bt-dropdown-menu__group {
  padding: var(--space-sm);
  font-size: var(--typography-font-size-xs);
  font-weight: 500;
  line-height: var(--typography-line-height-xs);
  color: var(--text-secondary);
}

/* ── Separator ───────────────────────────────────────────────────────────── */
.bt-dropdown-menu__separator {
  padding: var(--space-xs) 0;
}

/**
 * BTDropdownMenu — public API types.
 * Figma: container node 736-1793 · item node 736-1848.
 *
 * Single flat entry type — type field selects the rendered row:
 *   - 'item' (default)  — action row with icon, label, subtext, kbd, right icon
 *   - 'separator'       — thin horizontal line (BTSeparator)
 *   - 'group'           — non-interactive section label (12px, text-secondary)
 */

export type BTDropdownMenuEntryType = 'item' | 'separator' | 'group';
export type BTDropdownMenuSide      = 'top' | 'bottom' | 'left' | 'right';
export type BTDropdownMenuAlign     = 'start' | 'center' | 'end';

/**
 * One entry in the items array.
 *
 * For 'separator': only `type` is used (all other fields ignored).
 * For 'group':     only `type` + `label` are used.
 * For 'item':      all fields apply; `type` may be omitted (defaults to 'item').
 *
 * @example
 * ```ts
 * import type { BTDropdownMenuEntry } from '@btech/ui-vue';
 *
 * const items: BTDropdownMenuEntry<string>[] = [
 *   { value: 'cut',  label: 'Cut',  kbd: ['⌘', 'X'] },
 *   { value: 'copy', label: 'Copy', kbd: ['⌘', 'C'] },
 *   { type: 'separator' },
 *   { type: 'group', label: 'Danger zone' },
 *   { value: 'delete', label: 'Delete', error: true },
 * ];
 * ```
 */
export interface BTDropdownMenuEntry<T = string> {
  /** Row kind. Defaults to 'item' when absent. */
  type?: BTDropdownMenuEntryType;

  // ── Item + Group ─────────────────────────────────────────────────────────
  /** Display text. Required for 'item' and 'group'. */
  label?: string;

  /** Unique identifier returned in the 'select' emit. Required for 'item'. */
  value?: T;

  /** Secondary line below label. 'item' only. */
  subtext?: string;

  /**
   * Left icon.
   * Vue:   pass a Vue Component reference — rendered via <component :is="...">
   *        e.g. leftIcon: PhCopyIcon  (Phosphor, Material, any component)
   * React: pass a ReactNode — e.g. leftIcon: <Copy size={16} />
   */
  leftIcon?: unknown;

  /**
   * Right icon (e.g. chevron for navigation hint).
   * Same type contract as leftIcon per framework.
   */
  rightIcon?: unknown;

  /**
   * Keyboard shortcut keys rendered as BTKbd badges side-by-side.
   * e.g. ['⌘', 'X'] renders ⌘ badge + X badge.
   * 'item' only.
   */
  kbd?: string[];

  /** Dims label to text-disabled and prevents click. 'item' only. */
  disabled?: boolean;

  /**
   * Renders label in --color-ext-error.
   * Item remains clickable unless also disabled.
   * 'item' only.
   */
  error?: boolean;
}

export interface BTDropdownMenuProps<T = string> {
  /** Items to render — mix of 'item', 'group', 'separator' entries. */
  items: BTDropdownMenuEntry<T>[];

  /**
   * Controlled open state.
   * Vue: v-model:open   React: open + onOpenChange
   */
  open?: boolean;

  /**
   * Show BTInputSearch at top of panel.
   * RULE: always use BTInputSearch — never raw <input>.
   * Component does NOT auto-filter. Caller must filter items array.
   * @default false
   */
  hasSearch?: boolean;

  /**
   * Controlled search query.
   * Vue: v-model:searchQuery   React: searchQuery + onSearchChange
   * @default ''
   */
  searchQuery?: string;

  /** Panel width in px. @default 210 */
  width?: number;

  /** Panel side relative to trigger. @default 'bottom' */
  side?: BTDropdownMenuSide;

  /** Panel alignment relative to trigger. @default 'start' */
  align?: BTDropdownMenuAlign;

  /** Gap in px between trigger edge and panel. @default 4 */
  sideOffset?: number;

  /** Prevents trigger toggle — panel never opens. @default false */
  disabled?: boolean;
}

// ── Emits (Vue) / Callbacks (React) ─────────────────────────────────────────
// Vue emits:
//   'update:open'        (open: boolean)
//   'update:searchQuery' (query: string)
//   'select'             (value: T)
//
// React props:
//   onOpenChange?:   (open: boolean) => void
//   onSearchChange?: (query: string) => void
//   onSelect?:       (value: T) => void
//
// Trigger slot:
//   Vue:   <template #trigger="{ toggle, isOpen }"> ... </template>
//   React: trigger: ({ toggle, isOpen }) => ReactNode

export { default as BTDropdownMenu } from './BTDropdownMenu.vue';
export type {
  BTDropdownMenuEntry,
  BTDropdownMenuProps,
  BTDropdownMenuEntryType,
  BTDropdownMenuSide,
  BTDropdownMenuAlign,
} from './BTDropdownMenu.types';

/**
 * positionFloating — shared smart-flip positioning utility.
 *
 * Measures available space around a trigger element and places a floating
 * panel (already rendered in the DOM at position:fixed) below or above
 * depending on which direction has more room. Clamps horizontally so the
 * panel never overflows the viewport edges.
 *
 * Usage:
 *   // After the panel is in the DOM (watch flush:'post' or nextTick):
 *   positionBelow(triggerEl, panelEl, { gap: 4, margin: 8 });
 *
 * Also exported: positionDropdown — same algorithm but centres the panel
 * horizontally over an anchor element (for header pill dropdowns).
 */

export interface PositionOptions {
  /** Gap between trigger edge and panel edge. Default: 4. */
  gap?: number;
  /** Minimum distance from viewport edges. Default: 8. */
  margin?: number;
}

/**
 * Position a panel below or above `trigger`, left-aligned (then clamped).
 * Mutates `panel.style.top / left` and returns the resolved direction.
 */
export function positionBelow(
  trigger: HTMLElement,
  panel: HTMLElement,
  opts: PositionOptions = {},
): 'below' | 'above' {
  const { gap = 4, margin = 8 } = opts;
  const tRect = trigger.getBoundingClientRect();
  const pRect = panel.getBoundingClientRect();
  const vw = window.innerWidth;
  const vh = window.innerHeight;

  // ── Vertical: prefer below, flip above when there's not enough space ────────
  const spaceBelow = vh - tRect.bottom - gap;
  const spaceAbove = tRect.top - gap;
  const goAbove    = spaceBelow < pRect.height && spaceAbove >= pRect.height;

  const top = goAbove
    ? tRect.top  - pRect.height - gap
    : tRect.bottom + gap;

  // ── Horizontal: align to trigger start edge, clamp to viewport ─────────────
  const isRtl = getComputedStyle(trigger).direction === 'rtl';
  let left = isRtl ? tRect.right - pRect.width : tRect.left;
  if (left + pRect.width > vw - margin) left = vw - margin - pRect.width;
  if (left < margin)                    left = margin;

  panel.style.top  = `${Math.round(top)}px`;
  panel.style.left = `${Math.round(left)}px`;

  return goAbove ? 'above' : 'below';
}

export type PopoverSide   = 'top' | 'bottom' | 'left' | 'right';
export type PopoverAlign  = 'start' | 'center' | 'end';

/**
 * Position a popover panel relative to a trigger with auto-flip on all axes.
 * Respects the requested `side` but flips to the opposite if there is no room.
 */
export function positionPopover(
  trigger: HTMLElement,
  panel: HTMLElement,
  opts: { side?: PopoverSide; align?: PopoverAlign; sideOffset?: number; margin?: number } = {},
): void {
  const { side = 'bottom', align = 'start', sideOffset = 8, margin = 8 } = opts;
  const tRect = trigger.getBoundingClientRect();
  const pRect = panel.getBoundingClientRect();
  const vw = window.innerWidth;
  const vh = window.innerHeight;

  // ── Resolve side with auto-flip ─────────────────────────────────────────────
  let resolvedSide = side;
  if (side === 'bottom') {
    const fits = vh - tRect.bottom - sideOffset >= pRect.height;
    if (!fits && tRect.top - sideOffset >= pRect.height) resolvedSide = 'top';
  } else if (side === 'top') {
    const fits = tRect.top - sideOffset >= pRect.height;
    if (!fits && vh - tRect.bottom - sideOffset >= pRect.height) resolvedSide = 'bottom';
  } else if (side === 'right') {
    const fits = vw - tRect.right - sideOffset >= pRect.width;
    if (!fits && tRect.left - sideOffset >= pRect.width) resolvedSide = 'left';
  } else /* left */ {
    const fits = tRect.left - sideOffset >= pRect.width;
    if (!fits && vw - tRect.right - sideOffset >= pRect.width) resolvedSide = 'right';
  }

  // ── Main axis ───────────────────────────────────────────────────────────────
  let top  = 0;
  let left = 0;
  if      (resolvedSide === 'bottom') top  = tRect.bottom + sideOffset;
  else if (resolvedSide === 'top')    top  = tRect.top - pRect.height - sideOffset;
  else if (resolvedSide === 'right')  left = tRect.right  + sideOffset;
  else /* left */                     left = tRect.left  - pRect.width - sideOffset;

  // ── Cross axis (alignment) — flip start/end in RTL ──────────────────────────
  const isRtl = getComputedStyle(trigger).direction === 'rtl';
  const resolvedAlign = isRtl
    ? (align === 'start' ? 'end' : align === 'end' ? 'start' : align)
    : align;

  if (resolvedSide === 'top' || resolvedSide === 'bottom') {
    if      (resolvedAlign === 'start')  left = tRect.left;
    else if (resolvedAlign === 'center') left = tRect.left + tRect.width / 2 - pRect.width / 2;
    else /* end */                       left = tRect.right - pRect.width;

    // Clamp horizontally
    left = Math.min(left, vw - margin - pRect.width);
    left = Math.max(left, margin);
  } else {
    if      (align === 'start')  top = tRect.top;
    else if (align === 'center') top = tRect.top + tRect.height / 2 - pRect.height / 2;
    else /* end */               top = tRect.bottom - pRect.height;

    // Clamp vertically
    top = Math.min(top, vh - margin - pRect.height);
    top = Math.max(top, margin);
  }

  panel.style.top  = `${Math.round(top)}px`;
  panel.style.left = `${Math.round(left)}px`;
}

/**
 * Position a small dropdown centred horizontally over `anchor`, below or above.
 * Used by BTCalendarHeader month/year pills.
 */
export function positionCentered(
  anchor: HTMLElement,
  dropdown: HTMLElement,
  opts: PositionOptions = {},
): void {
  const { gap = 4, margin = 8 } = opts;
  const aRect = anchor.getBoundingClientRect();
  const dRect = dropdown.getBoundingClientRect();
  const vw = window.innerWidth;
  const vh = window.innerHeight;

  // Vertical: prefer below, flip above
  const spaceBelow = vh - aRect.bottom - gap;
  const spaceAbove = aRect.top - gap;
  const goAbove    = spaceBelow < dRect.height && spaceAbove >= dRect.height;

  const top = goAbove
    ? aRect.top  - dRect.height - gap
    : aRect.bottom + gap;

  // Horizontal: centre over anchor, clamp
  let left = aRect.left + aRect.width / 2 - dRect.width / 2;
  if (left + dRect.width > vw - margin) left = vw - margin - dRect.width;
  if (left < margin)                    left = margin;

  dropdown.style.top  = `${Math.round(top)}px`;
  dropdown.style.left = `${Math.round(left)}px`;
}
